export async function readFactsFromDb(c) {
  const doc = (await c.query("SELECT doc FROM accounts LIMIT 1")).rows[0].doc;
  return {
    account: { accountId: doc._id, name: doc.name, tier: doc.tier, region: doc.region },
    contract: doc.contract, contacts: doc.contacts,
    invoices: doc.invoices, shipments: doc.shipments,
    regulatoryFlags: doc.regulatoryFlags, supportCases: doc.supportCases, usage: doc.usage
  };
}
```

---

**Summary:** Found and returned the complete contents of both test files — `acceptance.test.mjs` (a workflow acceptance test that reads facts from a live PostgreSQL DB, runs the workflow, and asserts persisted state) and `facts.mjs` (an auto-generated oracle helper that reads account data from a JSONB `doc` column and re-exports `deriveExpected` from the benchmark scripts).

